const input = $input.first().json;
const action = input.action || 'repo_info';

const SUPABASE_URL = '{{SUPABASE_URL}}';
const SUPABASE_KEY = '{{SUPABASE_SERVICE_KEY}}';
const pgHeaders = {
  'apikey': SUPABASE_KEY,
  'Authorization': 'Bearer ' + SUPABASE_KEY
};

// Fetch all credentials in one query
const allCreds = await helpers.httpRequest({
  method: 'GET',
  url: SUPABASE_URL + '/rest/v1/template_credentials?template_id=eq.seafile&select=cred_key,cred_value',
  headers: pgHeaders
});
const creds = {};
for (const c of (allCreds || [])) creds[c.cred_key] = c.cred_value;

if (!creds.seafile_url) {
  return [{ json: { error: 'Seafile URL not configured. Use add_credential to set it up.' } }];
}
if (!creds.seafile_token) {
  return [{ json: { error: 'Seafile API token not configured. Use add_credential to set it up.' } }];
}

const baseUrl = creds.seafile_url.replace(/\/+$/, '');
const apiBase = baseUrl + '/api/v2.1/via-repo-token';
const sfHeaders = {
  'Authorization': 'Token ' + creds.seafile_token,
  'Accept': 'application/json'
};

function formatSize(bytes) {
  if (bytes >= 1073741824) return (bytes / 1073741824).toFixed(1) + ' GB';
  if (bytes >= 1048576) return (bytes / 1048576).toFixed(1) + ' MB';
  if (bytes >= 1024) return (bytes / 1024).toFixed(1) + ' KB';
  return bytes + ' B';
}

// === repo_info ===
if (action === 'repo_info') {
  try {
    const data = await helpers.httpRequest({ method: 'GET', url: apiBase + '/repo-info/', headers: sfHeaders });
    let result = '**' + data.repo_name + '**\n';
    result += 'ID: ' + data.repo_id + '\n';
    if (data.size !== undefined) result += 'Size: ' + formatSize(data.size) + '\n';
    if (data.file_count !== undefined) result += 'Files: ' + data.file_count + '\n';
    if (data.last_modified) result += 'Last modified: ' + data.last_modified + '\n';
    return [{ json: { result } }];
  } catch (err) {
    return [{ json: { error: 'Failed to get repo info: ' + err.message } }];
  }

// === list_directory ===
} else if (action === 'list_directory') {
  const path = input.path || '/';
  try {
    const data = await helpers.httpRequest({
      method: 'GET',
      url: apiBase + '/dir/?path=' + encodeURIComponent(path),
      headers: sfHeaders
    });
    const items = data.dirent_list || data;
    if (!items || items.length === 0) {
      return [{ json: { result: 'Directory "' + path + '" is empty.' } }];
    }
    const repoName = data.repo_name || '';
    let result = 'Contents of ' + path + (repoName ? ' (' + repoName + ')' : '') + ' — ' + items.length + ' items:\n\n';
    for (const item of items) {
      const icon = item.type === 'dir' ? '[dir]  ' : '[file] ';
      result += icon + item.name;
      if (item.size) result += ' (' + formatSize(item.size) + ')';
      if (item.modifier_name) result += ' — ' + item.modifier_name;
      result += '\n';
    }
    return [{ json: { result } }];
  } catch (err) {
    return [{ json: { error: 'Failed to list directory: ' + err.message } }];
  }

// === get_file_detail ===
} else if (action === 'get_file_detail') {
  const path = input.path;
  if (!path) return [{ json: { error: 'Parameter "path" is required.' } }];
  try {
    const data = await helpers.httpRequest({
      method: 'GET',
      url: apiBase + '/file/?path=' + encodeURIComponent(path),
      headers: sfHeaders
    });
    let result = '**' + (data.name || path.split('/').pop()) + '**\n';
    result += 'Path: ' + path + '\n';
    if (data.size !== undefined) result += 'Size: ' + formatSize(data.size) + '\n';
    if (data.last_modifier_name) result += 'Last modified by: ' + data.last_modifier_name + '\n';
    if (data.last_modified) result += 'Last modified: ' + data.last_modified + '\n';
    if (data.type) result += 'Type: ' + data.type + '\n';
    if (data.id) result += 'File ID: ' + data.id + '\n';
    return [{ json: { result } }];
  } catch (err) {
    return [{ json: { error: 'Failed to get file detail: ' + err.message } }];
  }

// === download_file ===
} else if (action === 'download_file') {
  const path = input.path;
  if (!path) return [{ json: { error: 'Parameter "path" is required.' } }];
  try {
    const downloadUrl = await helpers.httpRequest({
      method: 'GET',
      url: apiBase + '/download-link/?path=' + encodeURIComponent(path),
      headers: sfHeaders
    });
    const cleanUrl = String(downloadUrl).replace(/^"|"$/g, '');
    const textExts = ['.txt', '.md', '.json', '.csv', '.xml', '.yaml', '.yml', '.html', '.css', '.js', '.py', '.sh', '.log', '.ini', '.conf', '.cfg', '.toml', '.env', '.sql'];
    const ext = path.toLowerCase().substring(path.lastIndexOf('.'));
    if (textExts.includes(ext)) {
      try {
        const content = await helpers.httpRequest({ method: 'GET', url: cleanUrl, encoding: 'utf-8', returnFullResponse: false });
        const text = typeof content === 'string' ? content : JSON.stringify(content);
        if (text.length > 5000) {
          return [{ json: { result: 'File: ' + path + '\nDownload URL: ' + cleanUrl + '\n\nContent (truncated):\n' + text.substring(0, 5000) + '\n\n... (' + text.length + ' chars total)' } }];
        }
        return [{ json: { result: 'File: ' + path + '\nDownload URL: ' + cleanUrl + '\n\nContent:\n' + text } }];
      } catch (e) {
        // Fall through to returning just the URL
      }
    }
    return [{ json: { result: 'File: ' + path + '\nDownload URL: ' + cleanUrl + '\n\n(Binary file — use the download URL to access)' } }];
  } catch (err) {
    return [{ json: { error: 'Failed to get download link: ' + err.message } }];
  }

// === delete_file ===
} else if (action === 'delete_file') {
  const path = input.path;
  if (!path) return [{ json: { error: 'Parameter "path" is required.' } }];
  const isDir = input.is_dir === 'true' || input.is_dir === true;
  try {
    const endpoint = isDir ? '/dir/' : '/file/';
    await helpers.httpRequest({
      method: 'DELETE',
      url: apiBase + endpoint + '?path=' + encodeURIComponent(path),
      headers: sfHeaders
    });
    return [{ json: { result: 'Successfully deleted: ' + path } }];
  } catch (err) {
    return [{ json: { error: 'Failed to delete: ' + err.message } }];
  }

// === file_operation ===
} else if (action === 'file_operation') {
  const path = input.path;
  const operation = input.operation;
  if (!path || !operation) return [{ json: { error: 'Parameters "path" and "operation" (rename|move|copy) are required.' } }];
  if (!['rename', 'move', 'copy'].includes(operation)) {
    return [{ json: { error: 'Invalid operation "' + operation + '". Must be rename, move, or copy.' } }];
  }
  try {
    let formBody = 'operation=' + encodeURIComponent(operation);
    if (operation === 'rename') {
      if (!input.newname) return [{ json: { error: 'Parameter "newname" is required for rename.' } }];
      formBody += '&newname=' + encodeURIComponent(input.newname);
    } else {
      if (!input.dst_dir) return [{ json: { error: 'Parameter "dst_dir" is required for ' + operation + '.' } }];
      formBody += '&dst_dir=' + encodeURIComponent(input.dst_dir);
    }
    await helpers.httpRequest({
      method: 'POST',
      url: apiBase + '/file/?path=' + encodeURIComponent(path),
      headers: { ...sfHeaders, 'Content-Type': 'application/x-www-form-urlencoded' },
      body: formBody
    });
    if (operation === 'rename') {
      return [{ json: { result: 'Renamed "' + path + '" to "' + input.newname + '".' } }];
    } else {
      return [{ json: { result: operation.charAt(0).toUpperCase() + operation.slice(1) + 'd "' + path + '" to ' + input.dst_dir + '.' } }];
    }
  } catch (err) {
    return [{ json: { error: 'File operation failed: ' + err.message } }];
  }

// === create_file ===
} else if (action === 'create_file') {
  const path = input.path;
  const content = input.content;
  if (!path || content === undefined) return [{ json: { error: 'Parameters "path" (full file path) and "content" (file content) are required.' } }];
  const parts = path.replace(/^\//, '').split('/');
  const filename = parts.pop();
  const parentDir = '/' + parts.join('/');
  const replace = (input.replace === 'false' || input.replace === false) ? 0 : 1;
  try {
    const uploadUrl = await helpers.httpRequest({
      method: 'GET',
      url: apiBase + '/upload-link/?path=' + encodeURIComponent(parentDir || '/'),
      headers: sfHeaders
    });
    const cleanUploadUrl = String(uploadUrl).replace(/^"|"$/g, '');
    const boundary = '----n8nBoundary' + Date.now();
    let body = '--' + boundary + '\r\n';
    body += 'Content-Disposition: form-data; name="parent_dir"\r\n\r\n' + parentDir + '\r\n';
    body += '--' + boundary + '\r\n';
    body += 'Content-Disposition: form-data; name="replace"\r\n\r\n' + replace + '\r\n';
    body += '--' + boundary + '\r\n';
    body += 'Content-Disposition: form-data; name="file"; filename="' + filename + '"\r\n';
    body += 'Content-Type: text/plain\r\n\r\n' + content + '\r\n';
    body += '--' + boundary + '--\r\n';
    await helpers.httpRequest({
      method: 'POST',
      url: cleanUploadUrl + '?ret-json=1',
      headers: {
        'Authorization': 'Token ' + creds.seafile_token,
        'Content-Type': 'multipart/form-data; boundary=' + boundary
      },
      body: body
    });
    return [{ json: { result: 'File created: ' + path } }];
  } catch (err) {
    return [{ json: { error: 'Failed to create file: ' + err.message } }];
  }

} else {
  return [{ json: { error: 'Unknown action: ' + action + '. Available: repo_info, list_directory, get_file_detail, download_file, create_file, delete_file, file_operation.' } }];
}
